def calculate_relative_extrinsics(R_target_to_0, T_target_to_0, R_source_to_0, T_source_to_0):
    # Compute the relative rotation matrix from source to target
    R_target_to_source = np.dot(R_target_to_0, R_source_to_0.T)

    # Compute the relative translation vector from source to target
    T_target_to_source = T_target_to_0 - np.dot(R_target_to_source, T_source_to_0)

    return R_target_to_source, T_target_to_source

def cam_ext_setup(num_views, ext):
    N = num_views
    R_i2j = np.zeros((N,N,3,3))
    T_i2j = np.zeros((N,N,3))
        
    for i in range(N): # Target
        for j in range(N): # Source
            R_, T_ = calculate_relative_extrinsics(
                    ext[f"cam{j}"]["R"], 
                    ext[f"cam{j}"]["T"],
                    ext[f"cam{i}"]["R"], 
                    ext[f"cam{i}"]["T"])
            R_i2j[i, j] = R_
            T_i2j[i, j] = T_
    R_i2j = torch.tensor(R_i2j, dtype=torch.float32).cuda()
    T_i2j = torch.tensor(T_i2j, dtype=torch.float32).cuda()
    return R_i2j, T_i2j
